import { type Ref, useImperativeHandle, useState, useCallback } from 'react';
import { Accordion } from "react-bootstrap";
// import { useNavigate } from "react-router-dom";
import { type ICategoryRow } from '@/categories/types';

//import Q from '@/assets/Q.png';
//import A from '@/assets/A.png';
import type { AccordionEventKey } from 'react-bootstrap/esm/AccordionContext';
import type { IAccordionMethods } from '@/global/types';
import { faFolder } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { useCategoryContext } from './CategoryProvider';

//const PINK = 'rgba(255, 192, 203, 0.6)';
//const BLUE = 'rgb(224, 207, 252)';

type MapProps = {
    ref?: Ref<IAccordionMethods>;
    allCategoryRows: Map<string, ICategoryRow>;
};

const ChatBotDlgNavigator = ({ ref, allCategoryRows }: MapProps) => {

//const ChatBotDlgNavigator = forwardRef<IAccordionMethods, { allCategoryRows: Map<string, ICategoryRow> }>(
    // ({ allCategoryRows }, ref) => {

        const { expandNodesUpToTheTree } = useCategoryContext();
        // const navigate = useNavigate();
        // const linkGo = (link: string) => {
        //     //navigate(link);
        //     expandNodesUpToTheTree({ topId: '', id: link, parentId: null }, null, true);
        // }

        const [topRows, setTopRows] = useState<ICategoryRow[]>([]);

        /*
        function ContextAwareToggle({ children, eventKey, hasSubCategories, isExpanded, callback }:
            { children: ReactNode; eventKey: AccordionEventKey; hasSubCategories: boolean; isExpanded: boolean, callback?: (eventKey?: AccordionEventKey) => void }) {

            const { activeEventKey } = useContext(AccordionContext);
            const decoratedOnClick = useAccordionButton(
                String(eventKey ?? ''),
                () => callback && callback(eventKey),
            );
            const isCurrentEventKey = activeEventKey === eventKey;
            return (
                <Button
                    type="button"
                    //className={`${isExpanded ? '' : 'collapsed'} accordion-button${!hasSubCategories ? ' hide-icon' : ''}`}
                    className={`${!hasSubCategories ? ' hide-icon' : ''}`}
                    style={{
                        backgroundColor: isCurrentEventKey ? PINK : BLUE
                    }}
                    onClick={decoratedOnClick}
                >
                    {children}
                </Button>
            );
        }
        */

        const CatRow = ({ row }: { row: ICategoryRow }) => {
            const { topId, parentId, id, hasSubCategories, title, link } = row;
            console.log('CatRow', { id, hasSubCategories, title, link });
            //const myLink = link === '' ? `/categories/${topId}_${id}_null` : '';
            return (
                <Accordion.Item eventKey={id}>
                    <Accordion.Header className={`${!hasSubCategories ? 'hide-icon' : ''}`} onClick={() => {
                        expandNodesUpToTheTree(
                            { topId, id, parentId },
                            null,
                            true
                        )
                    }
                    }>
                        <FontAwesomeIcon icon={faFolder} size='sm' style={{ color: 'gray' }} />
                        {/* <ContextAwareToggle eventKey={row.id} hasSubCategories={row.hasSubCategories} isExpanded={row.isExpanded ? true : false}> */}
                        {row.link !== ''
                            ? <a href="#"
                                className="p-1 m-1 cat-link"
                            // onClick={() => linkGo(`${myLink}/from_chat`)}

                            >
                                {title}
                            </a>
                            : <span className="p-1 mx-1 title cat-title">{title}</span>
                        }
                        {/* </ContextAwareToggle> */}
                    </Accordion.Header>
                    <Accordion.Body>
                        {/* <Card.Body> */}
                        {row.hasSubCategories &&
                            <CatList rows={row.categoryRows} />
                        }
                        {/* </Card.Body> */}
                    </Accordion.Body>
                    {/* <Accordion.Collapse eventKey={row.id}>
                        <Card.Body>
                            {row.hasSubCategories &&
                                <CatList rows={row.categoryRows} />
                            }
                        </Card.Body>
                    </Accordion.Collapse> */}
                </Accordion.Item>
            )
        }

        const CatList = ({ rows }: { rows: ICategoryRow[] }) => {
            return (
                <>
                    {rows.map((row) => (
                        <CatRow key={row.id} row={row} />
                    ))}
                </>
            )
        }

        const onSelectCategory = async (eventKey: AccordionEventKey, e: React.SyntheticEvent<unknown>) => {
            const id = eventKey![0];
            console.log('onSelectCategory', { e, eventKey, id });
            // const cat = allCategoryRows.find(x => id === x.id);
            // if (cat) {
            //     /
            //     //cat.isExpanded = !cat.isExpanded;
            //     //e.stopPropagation();
            //     //e.preventDefault();
            // }
            // console.log('onSelectCategory', { cat, eventKey, e });
        }

        const loadSubTree = useCallback(async (catRow: ICategoryRow): Promise<boolean> => {
            const { id } = catRow;
            allCategoryRows.forEach(async (row) => {
                if (row.id !== id && row.parentId === id) {
                    await loadSubTree(row);
                    catRow.categoryRows.push(row);
                }
            });
            return true;
        }, [allCategoryRows]);

        //////////////////

        useImperativeHandle(ref, () => ({
            resetNavigator: () => {
                if (topRows.length > 0) {  
                    return
                }
                setTopRows([]);
                allCategoryRows.forEach(async (row) => {
                    row.categoryRows = [];
                    if (row.parentId === null) {
                        await loadSubTree(row);
                        setTopRows(prevTopRows => [...prevTopRows, row]);
                    }
                });
            }
        }), [loadSubTree, allCategoryRows]);


        return (
            <Accordion defaultActiveKey="" alwaysOpen={true} onSelect={onSelectCategory} className='category-bg'>
                <CatList rows={topRows}></CatList>
            </Accordion>
        );
    };

export default ChatBotDlgNavigator;